const item = $input.first().json;
const raw = (item.base64 || '').includes('base64,')
  ? item.base64.split('base64,')[1]
  : (item.base64 || '');
const buf = Buffer.from(raw, 'base64');
return [{
  json: { name: item.name || 'file', mimeType: item.mimeType || 'application/octet-stream' },
  binary: { data: buf }
}];
